INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (2, '五点', '场景', '要点中自然融入使用场景（如"办公室"、"旅行"、"健身房"）', 20, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (2, '五点', '信任背书', '符合大众用户心理学，例如：厌恶损失、从众心理', 21, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (2, '五点', '质保与售后', '包含数据背书（如"50000+五星评价"）或权威背书（如"FCC认证"）', 22, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (2, '五点', '流量词', '定期更新ARA排名快速上升的相关长尾词', 23, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (2, '五点', '易于AI理解', 'Listing中含有used for, capable of, is a, cause这4种关系的表达（注意：不一定是含有这4个关键词），最容易生成高质量的知识，因为带有这些关系的上下文最容易让算法理解，所以优先抓取这类信息。', 24, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (3, '标', '销量标：BS/AC/NR', 'BS/AC/NR标实际上利用的也是用户购物时的社会影响，BS/AC/NR标代表的也是该词/类目下大家都在买的产品推荐，利用从众，提升点击和转化（别人都在买的，我不知道买什么，那我也试试） ●BS标：短期内可以通过切换类目节点获得best seller 标，长期须以所在类目的bs1为目标，增加转化、点击 ●AC标：Amazon Choice：产品定位、主图及自然关键词、广告关键词重合度高才易获得 ●NR标：New Release。新品上架90天内通过迅速推广，获得同类新品第一，提高点击、转化', 25, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (3, '标', '活动标：BD/LD/DOTD/PD/黑五/网一', 'LD期间，控制进度条至80+% ●DEAL标：DOTD、BD、LD活动标志，通过活动价格提升转化率', 26, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (3, '标', '促销标：coupon/prime会员折扣/30day low price/code', '通过不同的折扣工具设定会有相应的标识出现，引导用户购买折扣商品 ●降价标：30天内最低价可获得。正红色，醒目，比一般折扣标更为有效，是短时间推广提升转化的利器 ●Coupon标：可按百分比、固定折扣金额两种方式设置', 27, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (3, '标', '服务标：ship from amazon/sold by amazon', '亚马逊配送和销售会增加顾客的信任度', 28, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (3, '标', '其他标：环保标/alexa', '欧美用户比较关注生态健康，具有环保标志会提升用户认可度，work with alexa是智能产品适配alexa的认证标', 29, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (3, '标', '叠加效应', '越多越好（BS的情况下，又有AC，且本周进行7DD（活动标），以及coupon），promotion', 30, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '划线价格', '通过设置合理的list price，获得划线价格，满足消费者占便宜的心理需求', 31, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '价格组合', '通过设置prime，coupon，code，promotion，B2B等多种价格组合方式，加大价格优惠力度。并在确保运营目标达成前提下，获得最佳转化率（优惠卷名称以英文产品名称+优惠）', 32, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '单只价格', '通过单只价格的设置加大价格感知和对比，给消费者更直观的价格感受', 33, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '定价策略', '市场/竞品定价：参考市场/竞品的定价区间，以略低于竞品的价格获取转化率优势', 34, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '定价策略', '活动定价：考虑DOTD、7DD、LD的活动价格折扣，在活动期间提升产品转化', 35, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '定价策略', '成本定价：参考产品毛利成本进行定价', 36, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '定价策略', '父体内价格策略：父体内不同子体形成一定的合理的价格差，设置低价引流款，提升转化', 37, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '定价策略', '定价尾数：不同地区客户偏好的定价尾数不一样，USA地区偏好尾数9，CA地区偏好尾数7', 38, NULL, 0);
INSERT INTO conversion_check_items (category_index, category_name, sub_dimension, standard, sort_order, user_id, is_custom) VALUES (4, '价格', '定价策略', '整数关口：利用消费者心理，设置9.99的整数关口，加大价格优惠感知', 39, NULL, 0);

